external_knowledge:
- 'Recent activities' refers to the latest recorded fitness metrics and workouts;
- 'Goal progress' involves determining if a fitness goal has been completed or is still in progress based on the progress percentage and completion status;
- 'Average statistics' include the mean values for workout duration, calories burned, and distance covered for workouts, as well as the mean values for steps, distance, and calories burned for fitness activities.

sql:
SELECT username
FROM users
WHERE user_id IN (SELECT user_id FROM goals);

SELECT AVG(steps) AS average_steps
FROM fitness_metrics
WHERE timestamp > DATETIME('now', '-30 days');

external_knowledge:
- 'Seasoned individuals' refers to users older than 30 years;
- 'Decent amount of steps' refers to 100 or more steps;
- 'Significant amount of calories' refers to 1000 or more calories;
- 'Vigorous average heart rate' means an average heart rate greater than 70;
- 'Covered a considerable distance' refers to a total distance traveled of over 10 miles.

sql:
SELECT SUM(calories_burned) AS total_calories_burned
FROM fitness_metrics
WHERE timestamp >= DATE('now', '-7 days');

external_knowledge:
- Active Users: Users who are physically active;
- Moderate Activity Threshold: Total steps taken > 10000;
- Relatively Calm Heart Rate: Average heart rate < 120 BPM;

sql:
SELECT SUM(steps) AS total_steps
FROM fitness_metrics
WHERE timestamp LIKE '2021-03-02%';

SELECT steps, calories_burned
FROM fitness_metrics
WHERE timestamp = (SELECT MAX(timestamp) FROM fitness_metrics);

external_knowledge:
- 'individuals aiming to lose weight' refers to users with a 'weight loss' goal; 
- 'latest health activity logged' means the most recent fitness metric recorded; 
- 'in the last few years' specifies the period from January 1, 2021, to January 1, 2023.

sql:
SELECT user_id, score
FROM leaderboards
WHERE score = (SELECT MAX(score) FROM leaderboards);
